#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 100
#define MAX_M 450
#define MOD 232

// Structure to represent a road
typedef struct {
    int city1;
    int city2;
    int cost;
} Road;

// Function to find all possible subtrees
void findSubtrees(int n, int m, Road roads[], int maxCost, int *cnt, int *maxCostFound, int *cntFound) {
    // Initialize the maximum cost and the count of subtrees
    *maxCostFound = 0;
    *cntFound = 0;

    // Iterate over all possible subtrees
    for (int i = 0; i < (1 << n); i++) {
        int subtreeCost = 0;
        int subtreeCnt = 0;
        int degree = 0;

        // Iterate over all roads
        for (int j = 0; j < m; j++) {
            // Check if the road is in the current subtree
            if ((i & (1 << roads[j].city1)) && (i & (1 << roads[j].city2))) {
                subtreeCost += roads[j].cost;
                subtreeCnt++;
                degree++;
            }
        }

        // Check if the subtree satisfies the conditions
        if (subtreeCnt > 0 && degree <= 3 * n && subtreeCost > *maxCostFound) {
            *maxCostFound = subtreeCost;
            *cntFound = 1;
        } else if (subtreeCost == *maxCostFound && subtreeCnt > 0) {
            (*cntFound)++;
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);

        Road roads[MAX_M];
        for (int i = 0; i < m; i++) {
            scanf("%d %d %d", &roads[i].city1, &roads[i].city2, &roads[i].cost);
        }

        int maxCost = 0;
        int cnt = 0;
        int maxCostFound = 0;
        int cntFound = 0;

        findSubtrees(n, m, roads, maxCost, &cnt, &maxCostFound, &cntFound);

        printf("%d %d\n", maxCostFound, cntFound % MOD);
    }

    return 0;
}

