import java.util.Scanner;
public class Main {
    static final int MAX_N = 100;
    static final int MAX_M = 450;
    static final int MOD = 232;

    // Structure to represent a road
    static class Road {
        int city1;
        int city2;
        int cost;

        public Road(int city1, int city2, int cost) {
            this.city1 = city1;
            this.city2 = city2;
            this.cost = cost;
        }
    }

    // Function to find all possible subtrees
    public static void findSubtrees(int n, int m, Road[] roads, int maxCost, int[] cnt, int[] maxCostFound, int[] cntFound) {
        // Initialize the maximum cost and the count of subtrees
        maxCostFound[0] = 0;
        cntFound[0] = 0;

        // Iterate over all possible subtrees
        for (int i = 0; i < (1 << n); i++) {
            int subtreeCost = 0;
            int subtreeCnt = 0;
            int degree = 0;

            // Iterate over all roads
            for (int j = 0; j < m; j++) {
                // Check if the road is in the current subtree
                if ((i & (1 << roads[j].city1)) != 0 && (i & (1 << roads[j].city2)) != 0) {
                    subtreeCost += roads[j].cost;
                    subtreeCnt++;
                    degree++;
                }
            }

            // Check if the subtree satisfies the conditions
            if (subtreeCnt > 0 && degree <= 3 * n && subtreeCost > maxCostFound[0]) {
                maxCostFound[0] = subtreeCost;
                cntFound[0] = 1;
            } else if (subtreeCost == maxCostFound[0] && subtreeCnt > 0) {
                cntFound[0]++;
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();

        while (t-- > 0) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();

            Road[] roads = new Road[m];
            for (int i = 0; i < m; i++) {
                roads[i] = new Road(scanner.nextInt(), scanner.nextInt(), scanner.nextInt());
            }

            int maxCost = 0;
            int[] cnt = new int[1];
            int[] maxCostFound = new int[1];
            int[] cntFound = new int[1];

            findSubtrees(n, m, roads, maxCost, cnt, maxCostFound, cntFound);

            System.out.println(maxCostFound[0] + " " + cntFound[0] % MOD);
        }
    }
}

